// Problem.jsx
import React from 'react';
import { useParams } from 'react-router-dom';

function Problem() {
  const { id } = useParams();

  return (
    <div>
      <h1>Problem Detail</h1>
      <p>Problem ID: {id}</p>
      {/* Fetch and display problem details based on id */}
    </div>
  );
}

export default Problem;
